import React from 'react';
import { Button, Slideout } from '@linm-soft-org/linm-web-common-components';
import { useLocation, useNavigate } from 'react-router-dom';
import {
  canOpenSourceDocumentRow,
  openSourceDocumentView,
  resolveSourceDocumentViewUrl,
} from '../../utils/openSourceDocumentView';
import { wmsDocumentTypeLabel } from '../../utils/wmsDocumentDrillDown';
import { resolveWmsDocumentViewPath } from '../../utils/wmsDocumentDrillDown';
import { WmsReportDocumentFormEmbed } from './WmsReportDocumentFormEmbed';
import styles from './WmsSourceDocumentSlideout.module.css';

export type WmsSourceDocumentSlideoutProps = {
  isOpen: boolean;
  onClose: () => void;
  documentType: string | null;
  documentId: string | null;
  sourceDocumentViewUrl?: string | null;
  voucherCode?: string;
  title: string;
  closeLabel: string;
  openFullLabel: string;
  testIdPrefix: string;
  returnTitle?: string;
};

export const WmsSourceDocumentSlideout: React.FC<WmsSourceDocumentSlideoutProps> = ({
  isOpen,
  onClose,
  documentType,
  documentId,
  sourceDocumentViewUrl,
  voucherCode,
  title,
  closeLabel,
  openFullLabel,
  testIdPrefix,
  returnTitle,
}) => {
  const navigate = useNavigate();
  const location = useLocation();
  const slideoutTitle = voucherCode
    ? `${title}: ${voucherCode}`
    : documentType
      ? `${title}: ${wmsDocumentTypeLabel(documentType)}`
      : title;

  const canEmbed = Boolean(
    documentType
    && documentId
    && resolveWmsDocumentViewPath(documentType, documentId),
  );

  const canOpenFull = canOpenSourceDocumentRow({
    sourceDocumentViewUrl,
    sourceDocumentType: documentType,
    canOpenSourceDocument: Boolean(documentType && documentId),
  });

  const handleOpenFull = () => {
    const path = resolveSourceDocumentViewUrl({
      sourceDocumentViewUrl,
      canOpenSourceDocument: Boolean(documentType && documentId),
    });
    if (!path) return;
    openSourceDocumentView({
      sourceDocumentViewUrl: path,
      title: voucherCode || path,
      returnPath: location.pathname + location.search,
      returnTitle,
      documentType,
      navigate,
    });
    onClose();
  };

  const footer = (
    <div className={styles.footerBar}>
      <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-slideout-close`}>
        {closeLabel}
      </Button>
      <Button
        variant="primary"
        onClick={handleOpenFull}
        disabled={!canOpenFull}
        data-testid={`${testIdPrefix}-slideout-open-full`}
      >
        {openFullLabel}
      </Button>
    </div>
  );

  return (
    <Slideout
      isOpen={isOpen}
      onClose={onClose}
      title={slideoutTitle}
      width="min(960px, 92vw)"
      customFooter={footer}
      data-testid={`${testIdPrefix}-document-slideout`}
    >
      {isOpen && documentType && documentId && canEmbed ? (
        <WmsReportDocumentFormEmbed
          documentType={documentType}
          documentId={documentId}
          testIdPrefix={testIdPrefix}
        />
      ) : isOpen && documentType && documentId ? (
        <div className={styles.unsupported} data-testid={`${testIdPrefix}-slideout-unsupported`}>
          Không hỗ trợ loại chứng từ này.
        </div>
      ) : null}
    </Slideout>
  );
};
