import React from 'react';
import { FormEmbedProvider } from '../form/FormEmbedContext';
import PnkFormPage from '../../pages/kho/PnkFormPage/PnkFormPage';
import PxkFormPage from '../../pages/kho/PxkFormPage/PxkFormPage';
import { resolveWmsDocumentViewPath } from '../../utils/wmsDocumentDrillDown';
import styles from './WmsSourceDocumentSlideout.module.css';

const DOCUMENT_FORMS: Record<string, React.ReactNode> = {
  GoodsReceipt: <PnkFormPage />,
  MaterialIssue: <PxkFormPage />,
};

export type WmsReportDocumentFormEmbedProps = {
  documentType: string;
  documentId: string;
  testIdPrefix: string;
};

export const WmsReportDocumentFormEmbed: React.FC<WmsReportDocumentFormEmbedProps> = ({
  documentType,
  documentId,
  testIdPrefix,
}) => {
  const path = resolveWmsDocumentViewPath(documentType, documentId);
  const form = DOCUMENT_FORMS[documentType];

  if (!path || !form) {
    return (
      <div className={styles.unsupported} data-testid={`${testIdPrefix}-slideout-unsupported`}>
        Không hỗ trợ loại chứng từ này.
      </div>
    );
  }

  return (
    <FormEmbedProvider mode="slideout" documentId={documentId}>
      <div className={styles.formEmbed} data-testid={`${testIdPrefix}-slideout-form-embed`}>
        {form}
      </div>
    </FormEmbedProvider>
  );
};
